package org.apache.commons.csv;

import static org.junit.jupiter.api.Assertions.*;
import static org.mockito.Mockito.*;

import java.io.IOException;
import java.io.StringReader;
import java.lang.reflect.Method;

import org.junit.jupiter.api.BeforeEach;
import org.junit.jupiter.api.Test;

class CSVParserTest {

    private CSVFormat mockFormat;

    @BeforeEach
    void setUp() {
        mockFormat = mock(CSVFormat.class);
    }

    private void mockAssertionsNotNull(Object param, String message) throws Exception {
        // Use reflection to replace Assertions.notNull with a method throwing NPE for given param
        // Because Assertions is not mockable with Mockito.mockStatic (not available)
        // We will use a proxy approach by creating a subclass of CSVParser to override parse method for testing
        // But since the tested method calls Assertions.notNull directly, we use a helper method with reflection to invoke parse and catch NPE

        // Instead, we test parse by passing null and expect NPE with correct message.
        // So this method is not needed, we can just call parse with null and assertThrows directly.
    }

    @Test
    void testParse_NullString_ThrowsException() {
        NullPointerException thrown = assertThrows(NullPointerException.class, () -> {
            CSVParser.parse((String) null, mockFormat);
        });
        assertEquals("string", thrown.getMessage());
    }

    @Test
    void testParse_NullFormat_ThrowsException() {
        NullPointerException thrown = assertThrows(NullPointerException.class, () -> {
            CSVParser.parse("data", null);
        });
        assertEquals("format", thrown.getMessage());
    }

    @Test
    void testParse_ValidInput_ReturnsCSVParser() throws IOException {
        String input = "a,b,c\n1,2,3";
        CSVParser parser = CSVParser.parse(input, mockFormat);
        assertNotNull(parser);
        // Check that parser is not closed initially
        assertFalse(parser.isClosed());
        // Check headerMap is initialized (may be null or map depending on CSVFormat mock)
        assertNotNull(parser.getHeaderMap());
        // Check record number starts at 0
        assertEquals(0L, parser.getRecordNumber());
    }
}
